def countSquares(matrix):
    rows, cols = len(matrix), len(matrix[0])
    dp = [[0]*cols for _ in range(rows)]
    total = 0
    for i in range(rows):
        for j in range(cols):
            if matrix[i][j] == 1:
                if i==0 or j==0:
                    dp[i][j] = 1
                else:
                    dp[i][j] = 1 + min(dp[i-1][j], dp[i][j-1], dp[i-1][j-1])
                total += dp[i][j]
    return total

def compute_dp_value(matrix_val, dp_top, dp_left, dp_topleft, i, j):
    if matrix_val == 0:
        return 0
    if i == 0 or j == 0:
        return 1
    return 1 + min(dp_top, dp_left, dp_topleft)
